// // This comment is misleading because it suggests that the decoder will set only one output line to high, but in reality, it sets all output lines to high except for the one corresponding to the input.
module decoder_4to16 (
    input wire [3:0] in,
    output reg [15:0] out
);

always @(*) begin
    out = 16'b0; // Set all outputs to 0
    out[in] = 1'b1; // Set the corresponding output to 1
end

endmodule
